import React, { useState } from 'react';

const MAX = 5;

export default function SearchHistory() {
  const [query, setQuery] = useState('');
  const [history, setHistory] = useState(['react hooks', 'css grid']);
  const [focused, setFocused] = useState(false);
  const [lastRun, setLastRun] = useState('');

  const submit = (q) => {
    const t = q.trim();
    if (!t) return;
    setHistory((h) => [t, ...h.filter((x) => x !== t)].slice(0, MAX));
    setLastRun(t);
    setFocused(false);
  };

  const reuse = (q) => {
    setQuery(q);
    submit(q);
  };

  return (
    <div style={{ maxWidth: 320 }}>
      <form
        onSubmit={(e) => {
          e.preventDefault();
          submit(query);
        }}
        style={{ display: 'flex', gap: 8 }}
      >
        <div style={{ position: 'relative', flex: 1 }}>
          <input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => setFocused(true)}
            onBlur={() => setFocused(false)}
            placeholder="Search…"
            style={{ width: '100%', padding: 8, boxSizing: 'border-box' }}
          />
          {focused && history.length > 0 && (
            <ul style={{ position: 'absolute', top: '100%', left: 0, right: 0, margin: '4px 0 0', padding: 4, listStyle: 'none', border: '1px solid #ddd', borderRadius: 8, background: '#fff', boxShadow: '0 6px 20px rgba(0,0,0,0.12)', zIndex: 10 }}>
              <li style={{ display: 'flex', justifyContent: 'space-between', padding: '4px 8px', color: '#888', fontSize: 12 }}>
                <span>Recent</span>
                <button type="button" onMouseDown={() => setHistory([])} style={{ border: 'none', background: 'none', color: '#2563eb', cursor: 'pointer' }}>Clear</button>
              </li>
              {history.map((h) => (
                <li
                  key={h}
                  onMouseDown={() => reuse(h)}
                  style={{ padding: '8px', cursor: 'pointer', borderRadius: 6 }}
                >
                  🔍 {h}
                </li>
              ))}
            </ul>
          )}
        </div>
        <button style={{ padding: '8px 14px', cursor: 'pointer' }}>Search</button>
      </form>
      {lastRun && <p style={{ color: '#16a34a' }}>Searched: “{lastRun}”</p>}
    </div>
  );
}

