import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-search-history',
  template: `
    <div style="max-width: 320px;">
      <form (submit)="$event.preventDefault(); submit(query)" style="display: flex; gap: 8px;">
        <div style="position: relative; flex: 1;">
          <input
            [value]="query"
            (input)="query = $any($event.target).value"
            (focus)="focused = true"
            (blur)="focused = false"
            placeholder="Search…"
            style="width: 100%; padding: 8px; box-sizing: border-box;"
          />
          <ul
            *ngIf="focused && history.length"
            style="position: absolute; top: 100%; left: 0; right: 0; margin: 4px 0 0; padding: 4px; list-style: none; border: 1px solid #ddd; border-radius: 8px; background: #fff; box-shadow: 0 6px 20px rgba(0,0,0,0.12); z-index: 10;"
          >
            <li style="display: flex; justify-content: space-between; padding: 4px 8px; color: #888; font-size: 12px;">
              <span>Recent</span>
              <button type="button" (mousedown)="clear()" style="border: none; background: none; color: #2563eb; cursor: pointer;">Clear</button>
            </li>
            <li
              *ngFor="let h of history"
              (mousedown)="reuse(h)"
              style="padding: 8px; cursor: pointer; border-radius: 6px;"
            >🔍 {{ h }}</li>
          </ul>
        </div>
        <button style="padding: 8px 14px; cursor: pointer;">Search</button>
      </form>
      <p *ngIf="lastRun" style="color: #16a34a;">Searched: “{{ lastRun }}”</p>
    </div>
  `,
})
export class SearchHistoryComponent {
  readonly MAX = 5;
  query = '';
  history: string[] = ['angular signals', 'rxjs operators'];
  focused = false;
  lastRun = '';

  submit(q: string): void {
    const t = q.trim();
    if (!t) {
      return;
    }
    this.history = [t, ...this.history.filter((x) => x !== t)].slice(0, this.MAX);
    this.lastRun = t;
    this.focused = false;
  }

  reuse(q: string): void {
    this.query = q;
    this.submit(q);
  }

  clear(): void {
    this.history = [];
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Search History Demo</h1>
      <app-search-history></app-search-history>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, SearchHistoryComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
